    int numero, minimo, massimo, somma=0;

    for(int i=0; i&lt;100; i++){
        numero = rand() % 1001;
        printf("%d ", numero);

        if(i==0)
            minimo = massimo = numero;
        else {
            if(numero &lt; minimo)
                minimo = numero;
            if(numero &gt; massimo)
                massimo = numero;
        }
        somma += numero;
