}

double grad_rad(double gradi){
    return gradi * M_PI / 180.0;
}

long double fattoriale(int n){
    if(n == 0)
        return 1;
    return n * fattoriale(n-1);
}

long double sen_taylor(double x, int n){
    if(n &lt; 0)
        return 0;
    return pow(-1, n) * pow(x, 2*n+1) / fattoriale(2*n+1) + sen_taylor(x, n-1);
}
